// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

/**
 * @title RiteForgeToken
 * @dev Standard ERC20 token with owner mint/burn capabilities
 */
contract RiteForgeToken is ERC20 {
    address public owner;
    address public masterContract;

    modifier onlyMasterOrOwner() {
        require(msg.sender == masterContract || msg.sender == owner, "Not authorized");
        _;
